const express = require('express');
const axios = require('axios');

const app = express();
app.use(express.json());

const llmModel = 'text-davinci-003';
const llmApiKey = 'YOUR_LLM_API_KEY';

app.post('/generate-code', async (req, res) => {
  const prompt = req.body.prompt;
  if (!prompt) {
    return res.status(400).send({ error: 'Prompt is required' });
  }

  try {
    const response = await axios.post(`https://api.openai.com/v1/engines/${llmModel}/completions`, {
      prompt,
      max_tokens: 2048,
      temperature: 0.7,
      top_p: 1,
      n: 1,
      stop: ['\n'],
    }, {
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${llmApiKey}`,
      },
    });

    const generatedCode = response.data.choices[0].text;
    res.send(generatedCode);
  } catch (error) {
    console.error(error);
    res.status(500).send({ error: 'Failed to generate code' });
  }
});

app.listen(3000, () => {
  console.log('Server listening on port 3000');
});